// Throwable
//   ├── Error          (JVM failures — do NOT catch)
//   │     ├── OutOfMemoryError
//   │     ├── StackOverflowError
//   │     └── AssertionError
//   └── Exception
//         ├── IOException          (checked)
//         ├── SQLException         (checked)
//         ├── CloneNotSupportedException (checked)
//         └── RuntimeException     (unchecked)
//               ├── NullPointerException
//               ├── IllegalArgumentException
//               ├── IllegalStateException
//               ├── IndexOutOfBoundsException
//               └── UnsupportedOperationException

// Checked — caller MUST handle
public void readFile(String path) throws IOException {
    Files.readAllBytes(Path.of(path));
}

// Unchecked — no throws declaration needed
public void setAge(int age) {
    if (age < 0) throw new IllegalArgumentException("age < 0: " + age);
    this.age = age;
}

// Common mistake: using checked exceptions for programming errors
// Don't do this:
public void processOrder(Order order) throws NullPointerException { // pointless declaration
    Objects.requireNonNull(order);  // just throw unchecked directly
}

// Multi-catch (Java 7+)
try {
    process();
} catch (IOException | SQLException e) {
    log.error("Data operation failed", e);
    throw new ServiceException("Operation failed", e); // chain!
}

// Exception chaining — always pass the cause
public void load(String path) {
    try {
        Files.readAllBytes(Path.of(path));
    } catch (IOException e) {
        // BAD: throw new RuntimeException("load failed"); // loses root cause
        throw new RuntimeException("load failed: " + path, e); // GOOD: chain
    }
}

// Inspect the chain
Throwable cause = e.getCause();       // immediate cause
Throwable root  = ExceptionUtils.getRootCause(e); // deepest cause (Apache Commons)

Connection conn = null;
try {
    conn = dataSource.getConnection();
    return conn.prepareStatement(sql).executeQuery();
} catch (SQLException e) {
    log.error("Query failed", e);
    throw new DataAccessException(e);
} finally {
    // Always runs — even if catch re-throws
    if (conn != null) {
        try { conn.close(); } catch (SQLException ignore) {}
    }
}

// Subtle bug: finally with return SUPPRESSES exceptions
try {
    throw new RuntimeException("oops");
} finally {
    return 42; // exception silently swallowed — NEVER do this
}

// try-with-resources — preferred over manual finally
try (InputStream in = new FileInputStream(src);
     OutputStream out = new FileOutputStream(dst)) {
    in.transferTo(out);
} // both streams closed automatically in reverse order

// Accessing suppressed exceptions
try (MyResource r = new MyResource()) {
    r.process(); // throws IOException
} catch (IOException e) {
    Throwable[] suppressed = e.getSuppressed(); // close() exception if any
    for (Throwable s : suppressed) log.warn("Suppressed", s);
}

// Java 9+: use effectively-final variable in try ()
var conn = dataSource.getConnection();
try (conn) { // no need to re-declare
    conn.prepareStatement(sql).execute();
}

// Custom unchecked exception for domain violations
public class InsufficientFundsException extends RuntimeException {
    private final BigDecimal amount;
    private final BigDecimal balance;

    public InsufficientFundsException(BigDecimal amount, BigDecimal balance) {
        super(String.format("Cannot withdraw %.2f, balance is %.2f", amount, balance));
        this.amount = amount;
        this.balance = balance;
    }

    // Provide cause constructor for chaining
    public InsufficientFundsException(String message, Throwable cause) {
        super(message, cause);
        this.amount = BigDecimal.ZERO;
        this.balance = BigDecimal.ZERO;
    }

    public BigDecimal getAmount() { return amount; }
    public BigDecimal getBalance() { return balance; }
}

// Usage with type-safe handling
try {
    account.withdraw(amount);
} catch (InsufficientFundsException e) {
    // Type gives us structured data, not just a message string
    notifyUser(e.getBalance(), e.getAmount());
}

// Anti-pattern 1: swallowing
try { process(); } catch (Exception e) {} // NEVER

// Anti-pattern 2: too broad catch
try {
    parse(input);
} catch (Exception e) { // catches NullPointerException too!
    log.warn("parse failed");
}

// Anti-pattern 3: exceptions for flow control (slow)
try {
    return Integer.parseInt(s);
} catch (NumberFormatException e) {
    return defaultValue; // use s.matches("-?\\d+") check instead
}

// Anti-pattern 4: log AND rethrow = double log
catch (IOException e) {
    log.error("failed", e); // logged here
    throw new ServiceException(e); // AND again at caller — pick ONE
}

// Correct: rethrow with chain, log at the boundary
catch (IOException e) {
    throw new ServiceException("read failed", e); // log at REST layer only
}
